const query = $input.first().json.query || {};
const id = query.id || '';
const action = query.action || '';

if (!id || !action) {
  return [{ json: { error: true, html: '<h2>Brak wymaganych parametrów</h2>' } }];
}

const STATUS_FIELD = 'fldvigglUZz1WCh9w';
const FOLLOWUP_FIELD = 'fld63Dh1k7Q0EYX5X';

const updates = {};
let message = '';

switch (action) {
  case 'contacted':
    updates[STATUS_FIELD] = 'Kontakt';
    message = '\u2705 Status zmieniony na: Kontakt';
    break;
  case 'no_answer':
    updates[STATUS_FIELD] = 'Brak kontaktu';
    message = '\u274c Status zmieniony na: Brak kontaktu';
    break;
  case 'followup':
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    updates[FOLLOWUP_FIELD] = tomorrow.toISOString().split('T')[0];
    message = '\uD83D\uDCC5 Follow-up ustawiony na jutro';
    break;
  default:
    return [{ json: { error: true, html: '<h2>Nieznana akcja</h2>' } }];
}

return [{ json: { id, updates, message, error: false } }];

const current = $input.first().json;
const requested = $('Przygotuj dane').first().json;
const STATUS_FIELD = 'fldvigglUZz1WCh9w';

const currentStatus = (current.fields || current)[STATUS_FIELD] || '';
const requestedStatus = requested.updates[STATUS_FIELD] || '';

if (requestedStatus && currentStatus === requestedStatus) {
  return [{ json: { ...requested, skip: true, message: '\u2705 Status już ustawiony: ' + currentStatus } }];
}

return [{ json: { ...requested, skip: false } }];

const data = $('Sprawdź idempotentność').first().json;
const message = data.message;
const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>Szkody CRM</title></head><body style="font-family:Segoe UI,sans-serif;display:flex;justify-content:center;align-items:center;min-height:100vh;margin:0;background:#f5f5f5;"><div style="background:white;padding:40px;border-radius:12px;text-align:center;box-shadow:0 2px 8px rgba(0,0,0,0.1);max-width:400px;"><div style="font-size:48px;margin-bottom:16px;">' + message.charAt(0) + '</div><h2 style="color:#1a1a2e;margin:0 0 8px;">' + message + '</h2><p style="color:#6b7280;margin:0;">Możesz zamknąć tę kartę.</p></div></body></html>';
return [{ json: { html } }];

const errorHtml = $('Przygotuj dane').first().json.html || '<h2>Wystąpił błąd</h2>';
const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>Szkody CRM</title></head><body style="font-family:Segoe UI,sans-serif;display:flex;justify-content:center;align-items:center;min-height:100vh;margin:0;background:#f5f5f5;"><div style="background:white;padding:40px;border-radius:12px;text-align:center;box-shadow:0 2px 8px rgba(0,0,0,0.1);max-width:400px;"><div style="font-size:48px;margin-bottom:16px;">❌</div>' + errorHtml + '<p style="color:#6b7280;margin:0;">Spróbuj ponownie lub skontaktuj się z administratorem.</p></div></body></html>';
return [{ json: { html } }];
